    if not candidate.providedBy(iface):
        raise Invalid("Candidate does not provide the interface")

    for method in iface.interfaceMethods():
        if not hasattr(candidate, method):
            raise Invalid("Candidate does not define required method")

    for attr in iface.interfaceAttributes():
        if not hasattr(candidate, attr):
            raise Invalid("Candidate does not define required attribute")

    return True

